85	py::object to_float_ptr(uintptr_t input_ptr, int size, ggml_type type) {
86	  if (type < 0 || type >= GGML_TYPE_COUNT) {
87	    PyErr_SetString(PyExc_ValueError, "Invalid ggml_type");
88	    throw py::error_already_set();
89	  }
90	
91	  py::module torch = py::module::import("torch");
92	  py::dict kwargs;
93	  kwargs["dtype"] = torch.attr("float32");
94	  py::object tensor = torch.attr("empty")(size, **kwargs);
95	
96	  uintptr_t output_ptr = tensor.attr("data_ptr")().cast<uintptr_t>();
97	  float* output_float_ptr = reinterpret_cast<float*>(output_ptr);
98	
99	  try {
100	    to_float(reinterpret_cast<void*>(input_ptr), output_float_ptr, size, type);
101	  } catch (const std::exception& e) {
102	    PyErr_SetString(PyExc_RuntimeError, e.what());
103	    throw py::error_already_set();
104	  }
105	
106	  return tensor;
107	}
108	
109	py::object from_float_ptr(uintptr_t input_ptr, int size, ggml_type type) {
110	  if (type < 0 || type >= GGML_TYPE_COUNT) {
111	    PyErr_SetString(PyExc_ValueError, "Invalid ggml_type");
112	    throw py::error_already_set();
113	  }
114	
115	  py::module torch = py::module::import("torch");
116	
117	  size_t output_elem_bytes = ggml_type_size(type);
118	  size_t output_elem_count = (size + ggml_blck_size(type) - 1) / ggml_blck_size(type);
119	  size_t total_bytes = output_elem_count * output_elem_bytes;
120	
121	  py::dict kwargs;
122	  kwargs["dtype"] = torch.attr("uint8");
123	  py::object tensor = torch.attr("empty")(total_bytes, **kwargs);
124	
125	  uintptr_t output_ptr = tensor.attr("data_ptr")().cast<uintptr_t>();
126	  void* output_void_ptr = reinterpret_cast<void*>(output_ptr);
127	
128	  try {
129	    from_float(reinterpret_cast<float*>(input_ptr), output_void_ptr, size, type);
130	  } catch (const std::exception& e) {
131	    PyErr_SetString(PyExc_RuntimeError, e.what());
132	    throw py::error_already_set();
133	  }
134	
135	  return tensor;
136	}
