138	template <typename T>
139	std::vector<std::vector<uintptr_t>> void_ptr_nested_to_uint(const std::vector<std::vector<T*>>& input) {
140	  std::vector<std::vector<uintptr_t>> result;
141	  for (const auto& row : input) {
142	    std::vector<uintptr_t> new_row;
143	    for (auto ptr : row) {
144	      new_row.push_back(reinterpret_cast<uintptr_t>(ptr));
145	    }
146	    result.push_back(std::move(new_row));
147	  }
148	  return result;
149	}
150	
151	template <typename T>
152	std::vector<std::vector<T*>> uint_to_void_ptr_nested(const std::vector<std::vector<uintptr_t>>& input) {
153	  std::vector<std::vector<T*>> result;
154	  for (const auto& row : input) {
155	    std::vector<T*> new_row;
156	    for (auto val : row) {
157	      new_row.push_back(reinterpret_cast<T*>(val));
158	    }
159	    result.push_back(std::move(new_row));
160	  }
161	  return result;
162	}
