164	#define DEF_PTR_PROPERTY(cls, name)                                                  \
165	  def_property(                                                                      \
166	      #name, [](const cls& self) { return reinterpret_cast<uintptr_t>(self.name); }, \
167	      [](cls& self, uintptr_t val) { self.name = reinterpret_cast<void*>(val); })
168	
169	#define DEF_PTR_2D_PROPERTY(cls, name)                                                 \
170	  def_property(                                                                        \
171	      #name, [](const cls& self) { return void_ptr_nested_to_uint<void>(self.name); }, \
172	      [](cls& self, const std::vector<std::vector<uintptr_t>>& val) {                  \
173	        self.name = uint_to_void_ptr_nested<void>(val);                                \
174	      })
