384	template <typename MoeSftTP>
385	void bind_moe_sft_module(py::module_& moe_module, const char* name) {
386	  using MoeClass = TP_MOE_SFT<MoeSftTP>;
387	  using MoeBindings = MOESFTBindings<MoeSftTP>;
388	
389	  py::class_<MoeClass, MoE_Interface, std::shared_ptr<MoeClass>>(moe_module, name)
390	      .def(py::init<MOESFTConfig>())
391	      .def("warm_up_task", &MoeBindings::WarmUpBindings::cpuinfer_interface)
392	      .def("load_weights_task", &MoeBindings::LoadWeightsBindings::cpuinfer_interface)
393	      .def("forward_sft_task", &MoeBindings::ForwardSFTBindings::cpuinfer_interface)
394	      .def("backward_task", &MoeBindings::BackwardBindings::cpuinfer_interface)
395	      .def("update_lora_weights_task", &MoeBindings::UpdateLoRAWeightsBindings::cpuinfer_interface)
396	      .def("warm_up", &MoeClass::warm_up)
397	      .def("load_weights", &MoeClass::load_weights)
398	      .def("forward_sft", &MoeClass::forward_sft_binding)
399	      .def("backward", &MoeClass::backward_binding)
400	      .def("update_lora_weights", &MoeClass::update_lora_weights_binding)
401	      .def("prepare_and_save_bwd",
402	           [](MoeClass& self, intptr_t gate, intptr_t up, intptr_t down, const std::string& path) {
403	             self.prepare_and_save_bwd((void*)gate, (void*)up, (void*)down, path);
404	           })
405	      .def("submit_backward_repack", &MoeClass::submit_backward_repack)
406	      .def("wait_backward_repack", &MoeClass::wait_backward_repack);
407	}
