410	template <typename MoeTP>
411	void bind_moe_module(py::module_& moe_module, const char* name) {
412	  using MoeClass = TP_MOE<MoeTP>;
413	  using MoeBindings = MOEBindings<MoeTP>;
414	
415	  auto moe_cls = py::class_<MoeClass, MoE_Interface, std::shared_ptr<MoeClass>>(moe_module, name);
416	
417	  moe_cls.def(py::init<GeneralMOEConfig>())
418	      .def("warm_up_task", &MoeBindings::WarmUpBindings::cpuinfer_interface)
419	      .def("load_weights_task",
420	           py::overload_cast<std::shared_ptr<MoeClass>>(&MoeBindings::LoadWeightsBindings::cpuinfer_interface))
421	      .def("load_weights_task",
422	           py::overload_cast<std::shared_ptr<MoeClass>, const uintptr_t>(
423	               &MoeBindings::LoadWeightsBindings::cpuinfer_interface),
424	           py::arg("physical_to_logical_map"))
425	      // .def("forward_task", &MoeBindings::ForwardBindings::cpuinfer_interface)
426	      .def("forward_task",
427	           py::overload_cast<std::shared_ptr<MoeClass>, intptr_t, int, intptr_t, intptr_t, intptr_t, intptr_t>(
428	               &MoeBindings::ForwardBindings::cpuinfer_interface))
429	      .def("forward_task",
430	           py::overload_cast<std::shared_ptr<MoeClass>, intptr_t, int, intptr_t, intptr_t, intptr_t, intptr_t, bool>(
431	               &MoeBindings::ForwardBindings::cpuinfer_interface))
432	      .def("warm_up", &MoeClass::warm_up)
433	      .def("load_weights", &MoeClass::load_weights)
434	      .def("forward", &MoeClass::forward_binding);
435	
436	  // Bind write_weight_scale_to_buffer_task for MoE types that support it
437	  // Uses SFINAE to detect if MoeClass has write_weight_scale_to_buffer method
438	  if constexpr (requires { &MoeClass::write_weight_scale_to_buffer; }) {
439	    struct WriteWeightScaleToBufferBindings {
440	      struct Args {
441	        CPUInfer* cpuinfer;
442	        MoeClass* moe;
443	        int gpu_tp_count;
444	        int expert_id;
445	        std::vector<uintptr_t> w13_weight_ptrs;
446	        std::vector<uintptr_t> w13_scale_ptrs;
447	        std::vector<uintptr_t> w2_weight_ptrs;
448	        std::vector<uintptr_t> w2_scale_ptrs;
449	      };
450	
451	      static void inner(void* args) {
452	        Args* args_ = (Args*)args;
453	        args_->cpuinfer->enqueue(&MoeClass::write_weight_scale_to_buffer, args_->moe, args_->gpu_tp_count,
454	                                 args_->expert_id, args_->w13_weight_ptrs, args_->w13_scale_ptrs, args_->w2_weight_ptrs,
