1006	static void crash_handler(int signo, siginfo_t* /*info*/, void* /*ucontext*/) {
1007	  const char* head = "=== crash: signal received ===\n";
1008	  write(STDERR_FILENO, head, std::strlen(head));
1009	  cpptrace::generate_trace().print();
1010	  _exit(128 + signo);
1011	}
