1013	__attribute__((constructor)) static void install_handlers() {
1014	  struct sigaction sa;
1015	  std::memset(&sa, 0, sizeof(sa));
1016	  sa.sa_sigaction = &crash_handler;
1017	  sa.sa_flags = SA_SIGINFO;
1018	  sigemptyset(&sa.sa_mask);
1019	
1020	  sigaction(SIGSEGV, &sa, nullptr);
1021	  sigaction(SIGABRT, &sa, nullptr);
1022	}
