36	class CPUInfer {
37	 public:
38	  CPUInfer(int thread_num) {
39	    printf("CPUInfer[0x%lx]: Hello\n", (intptr_t)this);
40	    backend_ = new WorkerPool(thread_num);
41	    task_queue_ = new TaskQueue();
42	    for (int i = 0; i < (1 << 16); ++i) {
43	      ggml_table_f32_f16[i] = GGML_COMPUTE_FP16_TO_FP32(i);
44	    }
45	  }
46	  CPUInfer(int thread_num, int numa_id) {
47	    printf("CPUInfer[0x%lx]: Hello\n", (intptr_t)this);
48	    backend_ = new WorkerPool(thread_num, numa_id);
49	    task_queue_ = new TaskQueue();
50	    for (int i = 0; i < (1 << 16); ++i) {
51	      ggml_table_f32_f16[i] = GGML_COMPUTE_FP16_TO_FP32(i);
52	    }
53	  }
54	
55	  CPUInfer(WorkerPoolConfig config) {
56	    printf("CPUInfer[0x%lx]: Hello\n", (intptr_t)this);
57	    backend_ = new WorkerPool(config);
58	    task_queue_ = new TaskQueue();
59	    for (int i = 0; i < (1 << 16); ++i) {
60	      ggml_table_f32_f16[i] = GGML_COMPUTE_FP16_TO_FP32(i);
61	    }
62	  }
63	
64	  ~CPUInfer() {
65	    printf("CPUInfer[0x%lx]: Goodbye\n", (intptr_t)this);
66	    delete backend_;
67	    delete task_queue_;
68	  }
69	
70	  CPUInfer(const CPUInfer&) = delete;
71	  CPUInfer& operator=(const CPUInfer&) = delete;
72	  CPUInfer(CPUInfer&&) = delete;
73	  CPUInfer& operator=(CPUInfer&&) = delete;
74	
75	  template <typename Func, typename Obj, typename... Args>
76	  void enqueue(Func f, Obj* obj, Args... args) {
77	    task_queue_->enqueue([=]() { std::invoke(f, *obj, args...); });
78	  }
79	
80	  void submit(std::pair<intptr_t, intptr_t> params) {
81	    void (*func)(void*) = (void (*)(void*))params.first;
82	    void* args = (void*)params.second;
83	    *((CPUInfer**)args) = this;
84	    func(args);
85	  }
86	#ifndef KTRANSFORMERS_CPU_ONLY
87	  void submit_with_cuda_stream(intptr_t user_cuda_stream, std::pair<intptr_t, intptr_t> params) {
88	#if defined(KTRANSFORMERS_USE_CUDA) || defined(KTRANSFORMERS_USE_MUSA) || defined(KTRANSFORMERS_USE_ROCM) || \
89	    defined(KTRANSFORMERS_USE_MACA)
90	    void (*func)(void*) = (void (*)(void*))params.first;
91	    void* args = (void*)params.second;
92	    *((CPUInfer**)args) = this;
93	    cudaLaunchHostFunc((cudaStream_t)user_cuda_stream, (cudaHostFn_t)func, args);
94	#endif
95	  }
96	#endif
