98	  struct SyncArgs {
99	    CPUInfer* cpuinfer;
100	    size_t allow_n_pending;
101	  };
102	
103	  static void sync_(void* sync_args) {
104	    SyncArgs* args = (SyncArgs*)sync_args;
105	    args->cpuinfer->task_queue_->sync(args->allow_n_pending);
106	  }
107	
108	  void sync(size_t allow_n_pending = 0) {
109	    SyncArgs* args = new SyncArgs{this, allow_n_pending};
110	    sync_(args);
111	  }
