42	  if (!obj) {
43	    fprintf(stderr, "NUMA node %d not found.\n", this_numa);
44	    hwloc_topology_destroy(topology);
45	    return;
46	  }
47	
48	  auto ret = hwloc_set_membind(topology, obj->nodeset, HWLOC_MEMBIND_BIND,
49	                               HWLOC_MEMBIND_THREAD | HWLOC_MEMBIND_STRICT | HWLOC_MEMBIND_BYNODESET);
50	  if (ret != 0) {
51	    perror("hwloc_set_membind_nodeset");
52	  }
53	
54	  hwloc_topology_destroy(topology);
