313	  // DeepSeek V4-Flash 2604B routed experts, matching the trtllm
314	  // `gemm1_clamp_limit` and the sglang deep_gemm path's
315	  // `_apply_swiglu_limit`:
316	  //   gate = clamp(gate, max=limit)            // one-sided (silu input)
317	  //   up   = clamp(up, min=-limit, max=limit)  // symmetric
318	  // Read by `act_fn` in la/amx.hpp; non-zero only for MXFP4 today.
319	  // Origin: kt-sglang 耦合 (carries the V4-2604B limit set by sglang side).
320	  float swiglu_limit = 0.0f;
321	
322	  // MiniMax M3 "swigluoai" activation: gate * sigmoid(gate * alpha) * (up + 1).
323	  // When alpha > 0, act_fn uses the swigluoai formula with symmetric clamp on
324	  // both gate and up (±swiglu_limit). 0.0f = disabled (standard silu path).
325	  float swiglu_alpha = 0.0f;
