428	template <typename A, typename B>
429	void convert_or_copy(A* dst, const B* src, size_t count) {
430	  if constexpr (std::is_same_v<A, B>) {
431	    // printf("Direct copy\n");
432	    memcpy(dst, src, sizeof(A) * count);
433	  } else {
434	    if constexpr (std::is_same_v<A, float>) {
435	      if constexpr (std::is_same_v<B, ggml_bf16_t>) {
436	        // printf("Converting ggml_bf16_t to float\n");
437	        ggml_bf16_to_fp32_row(src, dst, count);
438	      } else if constexpr (std::is_same_v<B, ggml_fp16_t>) {
439	        ggml_fp16_to_fp32_row(src, dst, count);
440	      } else {
441	        throw std::runtime_error("Unsupported conversion");
442	      }
443	    } else if constexpr (std::is_same_v<A, ggml_bf16_t>) {
444	      if constexpr (std::is_same_v<B, float>) {
445	        // printf("Converting float to ggml_bf16_t\n");
446	        ggml_fp32_to_bf16_row(src, dst, count);
447	      } else {
448	        throw std::runtime_error("Unsupported conversion");
449	      }
450	    }
451	
452	    else {
453	      throw std::runtime_error("Unsupported conversion");
454	    }
455	  }
456	}
457	
458	template <typename A>
459	void convert_or_copy(A* dst, void* src, ggml_type type, size_t count) {
460	  switch (type) {
461	    case GGML_TYPE_BF16: {
462	      auto src_bf16 = (ggml_bf16_t*)src;
463	      convert_or_copy(dst, src_bf16, count);
464	      break;
465	    }
466	    case GGML_TYPE_F16: {
467	#if defined(__aarch64__) && defined(CPU_USE_KML)
468	      auto src_fp16 = (float16_t*)src;
469	      convert_or_copy(dst, src_fp16, count);
470	#else
471	      throw std::runtime_error("GGML_TYPE_F16 is not supported on this platform");
472	#endif
473	      break;
474	    }
475	    case GGML_TYPE_F32: {
476	      auto src_f32 = (float*)src;
477	      convert_or_copy(dst, src_f32, count);
478	      break;
479	    }
480	    default:
481	      throw std::runtime_error("Unsupported type for conversion");
482	  }
483	}
