485	template <typename A>
486	void check_numerics(A* data, size_t count) {
487	  for (size_t i = 0; i < count; i++) {
488	    if (std::isnan(data[i]) || std::isinf(data[i])) {
489	      printf("Numerics check failed at index %zu: value = %f\n", i, data[i]);
490	      throw std::runtime_error("Numerics check failed");
491	    }
492	  }
493	  printf("Numerics check passed for %zu elements.\n", count);
494	}
