248	                  T::BufferB::required_size(config_.intermediate_size, config_.hidden_size, PACKED, 'u', PLAIN);
249	              size_t size = whole_size_ - scale_size;
250	              void* dst_ = PLAIN ? gate_bb_[expert_id]->b : gate_bb_[expert_id]->b_pack[0];
251	
252	              memcpy(dst_, config_.gate_projs[tp_part_idx][logical_expert_id], size);
253	
254	              if constexpr (T::BufferB::SCALE) {
255	                memcpy(gate_bb_[expert_id]->d, config_.gate_scales[tp_part_idx][logical_expert_id], scale_size);
256	              }
257	
258	              whole_size_ =
259	                  T::BufferB::required_size(config_.intermediate_size, config_.hidden_size, PACKED, 'u', PLAIN);
260	              size = whole_size_ - scale_size;
261	              dst_ = PLAIN ? up_bb_[expert_id]->b : up_bb_[expert_id]->b_pack[0];
262	              memcpy(dst_, config_.up_projs[tp_part_idx][logical_expert_id], size);
263	
264	              if constexpr (T::BufferB::SCALE) {
265	                memcpy(up_bb_[expert_id]->d, config_.up_scales[tp_part_idx][logical_expert_id], scale_size);
266	              }
267	            }
268	
269	            {
270	              size_t scale_size = config_.hidden_size * sizeof(float);
271	              size_t whole_size_ =
272	                  T::BufferB::required_size(config_.hidden_size, config_.intermediate_size, PACKED, 'd', PLAIN);
273	              size_t size = whole_size_ - scale_size;
274	              void* dst_ = PLAIN ? down_bb_[expert_id]->b : down_bb_[expert_id]->b_pack[0];
275	              memcpy(dst_, config_.down_projs[tp_part_idx][logical_expert_id], size);
276	
277	              if constexpr (T::BufferB::SCALE) {
278	                memcpy(down_bb_[expert_id]->d, config_.down_scales[tp_part_idx][logical_expert_id], scale_size);
279	              }
280	            }
281	          },
282	          nullptr);
283	
284	    } else {
285	      static uint8_t mat_type_all = 3, mat_split = 1;
286	      if (config_.load) {
287	        std::cout << "Loading from " << prefix << std::endl;
288	        for (int task_id = 0; task_id < config_.expert_num * mat_type_all * mat_split; task_id++) {
289	          int64_t expert_idx = task_id / (mat_type_all * mat_split);
290	          uint8_t mat_class = (task_id % (mat_type_all * mat_split)) / mat_split;
291	          uint8_t mat_split_idex = task_id % mat_split;
292	          uint64_t logical_expert_id = expert_map(physical_to_logical_map, expert_idx);
293	          void* src_;
294	          if (mat_class == 0) {  // the up matrix
295	            src_ = PLAIN ? up_bb_[expert_idx]->b : up_bb_[expert_idx]->b_pack[0];
296	            size_t size = T::BufferB::required_size(config_.intermediate_size, config_.hidden_size, PACKED, 'u', PLAIN);
297	            size_t scale_size = config_.intermediate_size * sizeof(float);
298	            read_weights(prefix, "_up_", (char*)src_, logical_expert_id, size, scale_size, mat_split, mat_split_idex);
299	          } else if (mat_class == 1) {
300	            void* src_ = PLAIN ? gate_bb_[expert_idx]->b : gate_bb_[expert_idx]->b_pack[0];
301	            size_t size = T::BufferB::required_size(config_.intermediate_size, config_.hidden_size, PACKED, 'u', PLAIN);
302	            size_t scale_size = config_.intermediate_size * sizeof(float);
303	            read_weights(prefix, "_gate_", (char*)src_, logical_expert_id, size, scale_size, mat_split, mat_split_idex);
304	          } else {
305	            void* src_ = PLAIN ? down_bb_[expert_idx]->b : down_bb_[expert_idx]->b_pack[0];
306	            size_t size = T::BufferB::required_size(config_.hidden_size, config_.intermediate_size, PACKED, 'd', PLAIN);
307	            size_t scale_size = config_.hidden_size * sizeof(float);
308	            read_weights(prefix, "_down_", (char*)src_, logical_expert_id, size, scale_size, mat_split, mat_split_idex);
309	          }
310	        }
311	      }
312	// check process, store down matrix to check
313	#ifdef CHECK
314	      load_check();
315	#endif
316	#ifndef CHECK
317	      else
318	#endif
319	      {
320	        if (tp_part_idx == 0) {
321	          std::cout << "  online quant from bf16" << std::endl;
322	        }
323	        int nth = T::recommended_nth_up_gate(config_.intermediate_size);
324	        pool->do_work_stealing_job(
325	            nth * config_.expert_num, nullptr,
326	            [this, nth, physical_to_logical_map](int task_id) {
327	              int64_t expert_idx = task_id / nth;
328	              uint64_t logical_expert_id = expert_map(physical_to_logical_map, expert_idx);
329	              int ith = task_id % nth;
330	              // gate part
331	              gate_bb_[logical_expert_id]->from_mat(
332	                  (ggml_bf16_t*)config_.gate_proj + logical_expert_id * config_.intermediate_size * config_.hidden_size,
333	                  ith, nth, -1, PACKED, PLAIN);
334	              // up part
335	              up_bb_[logical_expert_id]->from_mat(
336	                  (ggml_bf16_t*)config_.up_proj + logical_expert_id * config_.intermediate_size * config_.hidden_size,
337	                  ith, nth, -1, PACKED, PLAIN);
338	            },
339	            nullptr);
340	
341	        nth = T::recommended_nth_down(config_.hidden_size);
342	        pool->do_work_stealing_job(
343	            nth * config_.expert_num, nullptr,
344	            [this, nth, physical_to_logical_map](int task_id) {
345	              int64_t expert_idx = task_id / nth;
346	              int ith = task_id % nth;
347	              uint64_t logical_expert_id = expert_map(physical_to_logical_map, expert_idx);
348	              // down part
349	              down_bb_[logical_expert_id]->from_mat(
350	                  (ggml_bf16_t*)config_.down_proj + logical_expert_id * config_.hidden_size * config_.intermediate_size,
351	                  ith, nth, -1, PACKED, PLAIN);
352	            },
353	            nullptr);
354	      }
355	#ifdef CHECK
356	      verify_load_right();
357	#endif
358	      // save process
359	      if (config_.save) {
360	        pool->do_work_stealing_job(
361	            config_.expert_num * mat_type_all, nullptr,
362	            [this, physical_to_logical_map](int task_id) {
363	              int64_t expert_idx = task_id / mat_type_all;
364	              expert_idx = expert_map(physical_to_logical_map, expert_idx);
365	              uint8_t mat_class = task_id % mat_type_all;
366	              if (mat_class == 0) {  // the up matrix
367	                size_t size =
368	                    T::BufferB::required_size(config_.intermediate_size, config_.hidden_size, PACKED, 'u', PLAIN);
369	                size_t scale_size = config_.intermediate_size * sizeof(float);
370	                write_weights(prefix, "_up_", (char*)up_bb_[expert_idx]->b_pack[0], expert_idx, size, scale_size);
371	              } else if (mat_class == 1) {
372	                size_t size =
373	                    T::BufferB::required_size(config_.intermediate_size, config_.hidden_size, PACKED, 'u', PLAIN);
374	                size_t scale_size = config_.intermediate_size * sizeof(float);
375	                write_weights(prefix, "_gate_", (char*)gate_bb_[expert_idx]->b_pack[0], expert_idx, size, scale_size);
376	              } else if (mat_class == 2) {
377	                size_t size =
378	                    T::BufferB::required_size(config_.hidden_size, config_.intermediate_size, PACKED, 'd', PLAIN);
379	                size_t scale_size = config_.hidden_size * sizeof(float);
380	                write_weights(prefix, "_down_", (char*)down_bb_[expert_idx]->b_pack[0], expert_idx, size, scale_size);
381	              }
382	            },
383	            nullptr);
384	      }
385	    }
386	  }
