388	  void warm_up() {
389	    int qlen = config_.max_len;
390	    std::vector<uint8_t> input(sizeof(input_t) * qlen * config_.hidden_size);
391	    std::vector<uint8_t> output(sizeof(output_t) * qlen * config_.hidden_size);
392	    std::vector<int64_t> expert_ids(qlen * config_.num_experts_per_tok);
393	    std::vector<float> weights(qlen * config_.num_experts_per_tok);
394	    for (int i = 0; i < qlen * config_.num_experts_per_tok; i++) {
395	      expert_ids[i] = i % config_.expert_num;
396	      weights[i] = 0.01;
397	    }
398	    forward(qlen, config_.num_experts_per_tok, expert_ids.data(), weights.data(), input.data(), output.data());
399	  }
