401	#define MOE_DIRECT_OR_POOL_BY_VAR(var, fn)                       \
402	  do {                                                           \
403	    if (var < 5) {                                               \
404	      for (int i = 0; i < (var); i++) {                          \
405	        (fn)(i);                                                 \
406	      }                                                          \
407	    } else {                                                     \
408	      pool->do_work_stealing_job((var), nullptr, (fn), nullptr); \
409	    }                                                            \
410	  } while (0)
411	  static float act_fn(float x) { return x / (1.0f + expf(-x)); }
412	
413	  void forward(int qlen, int k, const int64_t* expert_ids, const float* weights, const void* input, void* output) {
414	    // Unified forward path: 'd' for decode (qlen<=1), 'p' for prefill (qlen>1)
415	    char mode = (qlen <= 1) ? 'd' : 'p';
416	    forward_unified(mode, qlen, k, expert_ids, weights, input, output);
417	  }
