419	  // Helper to select B pointer for up or gate mat based on packing
420	  inline int8_t* select_up_or_gate_B_ptr_(bool do_up, int expert_idx, int ith, int devide_elements_size) {
421	    if constexpr (PLAIN) {
422	      int8_t* base = do_up ? (int8_t*)up_bb_[expert_idx]->b : (int8_t*)gate_bb_[expert_idx]->b;
423	      return base + ith * config_.hidden_size * T::N_BLOCK_UP_GATE / devide_elements_size;
424	    } else {
425	      return do_up ? (int8_t*)up_bb_[expert_idx]->b_pack[ith] : (int8_t*)gate_bb_[expert_idx]->b_pack[ith];
426	    }
427	  }
428	
429	  // Helper to select B pointer for down mat based on packing
430	  inline int8_t* select_down_B_ptr_(int expert_idx, int ith, int devide_elements_size) {
431	    if constexpr (PLAIN) {
432	      return ((int8_t*)down_bb_[expert_idx]->b) +
433	             ith * config_.intermediate_size * T::N_BLOCK_DOWN / devide_elements_size;
434	    } else {
435	      return (int8_t*)down_bb_[expert_idx]->b_pack[ith];
436	    }
437	  }
