439	  // Unified implementation for decode/prefill using mode 'd' or 'p'
440	  void forward_unified(char mode, int qlen, int k, const int64_t* expert_ids, const float* weights, const void* input,
441	                       void* output) {
442	    MatKernelVariant var = (mode == 'p') ? MatKernelVariant::Prefill : MatKernelVariant::Decode;
443	    MatKernelSelection kernel = select_mat_kernel<T>(var);
444	    GemmFn cblas_gemm_s8s8s32 = kernel.fn;
445	    int devide_elements_size = kernel.divide_elements_size;
446	
447	#ifdef FORWARD_TIME_PROFILE
448	    forward_perf_start();
449	#endif
450	    int max_local_num = 0;
451	
452	    auto pool = config_.pool->get_subpool(tp_part_idx);
453	
454	    int activated_expert = 0;
455	    for (int i = 0; i < config_.expert_num; i++) {
456	      m_local_num_[i] = 0;
457	    }
458	    for (int i = 0; i < qlen; i++) {
459	      for (int j = 0; j < k; j++) {
460	        if (config_.should_skip_expert(expert_ids[i * k + j])) {
461	          continue;
462	        }
463	        m_local_pos_[i][j] = m_local_num_[expert_ids[i * k + j]]++;
464	      }
465	    }
466	
467	    for (int i = 0; i < config_.expert_num; i++) {
468	      if (m_local_num_[i] > 0) {
469	        max_local_num = std::max(max_local_num, m_local_num_[i]);
470	        m_expert_id_map_[activated_expert] = i;
471	        activated_expert++;
472	      }
473	    }
474	
475	    uint64_t offset = 0;
476	    for (int i = 0; i < config_.expert_num; i++) {
477	      m_local_input_ptr_[i] = m_local_input_ + offset * config_.hidden_size;
478	      m_local_gate_output_ptr_[i] = m_local_gate_output_ + offset * config_.intermediate_size;
479	      m_local_up_output_ptr_[i] = m_local_up_output_ + offset * config_.intermediate_size;
480	      m_local_down_output_ptr_[i] = m_local_down_output_ + offset * config_.hidden_size;
481	      offset += m_local_num_[i];
482	    }
483	
484	#ifdef FORWARD_TIME_PROFILE
485	    PROFILE_RECORD_TIME_STAMP("prepare");
486	#endif
487	
488	    // Copy inputs into expert-local buffers
489	    MOE_DIRECT_OR_POOL_BY_VAR(qlen, [&](int i) {
490	      for (int j = 0; j < k; j++) {
491	        if (config_.should_skip_expert(expert_ids[i * k + j])) {
492	          continue;
493	        }
494	        memcpy(m_local_input_ptr_[expert_ids[i * k + j]] + m_local_pos_[i][j] * config_.hidden_size,
495	               (input_t*)input + i * config_.hidden_size, sizeof(input_t) * config_.hidden_size);
496	      }
497	    });
498	
499	#ifdef FORWARD_TIME_PROFILE
500	    PROFILE_RECORD_TIME_STAMP("copy_input");
501	#endif
502	
503	    // Quantize expert inputs (row-wise)
504	    {
505	      size_t mth = T::recommended_mth(max_local_num);
506	      MOE_DIRECT_OR_POOL_BY_VAR(activated_expert * mth, [&](int task_id) {
507	        int task_id_expert = task_id / mth;
508	        int ith = task_id % mth;
509	        int expert_idx = m_expert_id_map_[task_id_expert];
510	        if (ith * T::M_BLOCK >= m_local_num_[expert_idx]) return;
511	        gate_up_ba_[expert_idx]->from_mat(m_local_num_[expert_idx], m_local_input_ptr_[expert_idx], ith, mth);
512	      });
513	    }
514	
515	#ifdef FORWARD_TIME_PROFILE
516	    PROFILE_RECORD_TIME_STAMP("quant_input");
517	#endif
518	
519	    int nth_up = T::recommended_nth_up_gate(config_.intermediate_size, mode);
520	    int mth = T::recommended_mth(max_local_num);
521	    int32_t oc = 0;
522	
523	    // Up and Gate GEMMs + dequant scale
524	    pool->do_work_stealing_job(
525	        mth * nth_up * activated_expert * 2, nullptr,
526	        [this, qlen, nth_up, oc, &cblas_gemm_s8s8s32, devide_elements_size, mth](int task_id2) {
527	          int task_id = task_id2 / 2;
528	          bool do_up = task_id2 % 2;
529	          int expert_idx = m_expert_id_map_[task_id / (nth_up * mth)];
530	          task_id = task_id % (nth_up * mth);
531	          int ith = task_id % nth_up;
532	          int jth = task_id / nth_up;
533	          if (jth * T::M_BLOCK >= m_local_num_[expert_idx]) return;
534	          int m_block = T::M_BLOCK;
535	          if ((jth + 1) * T::M_BLOCK > m_local_num_[expert_idx]) {
536	            m_block = m_local_num_[expert_idx] - jth * T::M_BLOCK;
537	          }
538	          int8_t* a_ptr = (int8_t*)gate_up_ba_[expert_idx]->a + jth * T::M_BLOCK * config_.hidden_size;
539	          int8_t* b_ptr = select_up_or_gate_B_ptr_(do_up, expert_idx, ith, devide_elements_size);
540	          int32_t* c_ptr = (do_up ? (int32_t*)up_bc_[expert_idx]->c : (int32_t*)gate_bc_[expert_idx]->c) +
541	                           ith * T::N_BLOCK_UP_GATE + jth * T::M_BLOCK * config_.intermediate_size;
542	
543	          cblas_gemm_s8s8s32(KernelCblasRowMajor, KernelCblasNoTrans, KernelCblasTrans, KernelCblasFixOffset, m_block,
544	                             T::N_BLOCK_UP_GATE, config_.hidden_size, 1.0, a_ptr, config_.hidden_size, 0, b_ptr,
545	                             config_.hidden_size, 0, 0.0, c_ptr, config_.intermediate_size, &oc);
546	
547	          if (do_up) {
548	            T::apply_scale(m_local_num_[expert_idx], config_.intermediate_size, m_local_up_output_ptr_[expert_idx],
549	                           gate_up_ba_[expert_idx].get(), up_bb_[expert_idx].get(), up_bc_[expert_idx].get(), ith,
550	                           nth_up, T::N_BLOCK_UP_GATE, jth);
551	          } else {
552	            T::apply_scale(m_local_num_[expert_idx], config_.intermediate_size, m_local_gate_output_ptr_[expert_idx],
553	                           gate_up_ba_[expert_idx].get(), gate_bb_[expert_idx].get(), gate_bc_[expert_idx].get(), ith,
554	                           nth_up, T::N_BLOCK_UP_GATE, jth);
555	          }
556	        },
557	        nullptr);
558	
559	#ifdef FORWARD_TIME_PROFILE
560	    PROFILE_RECORD_TIME_STAMP("up_gate");
561	#endif
562	
563	    // Activate gate and multiply by up
564	    {
565	      int nth = T::recommended_nth(config_.intermediate_size);
566	      auto up_gate_fn = [this, nth](int task_id) {
567	        int expert_idx = m_expert_id_map_[task_id / nth];
568	        int ith = task_id % nth;
569	        auto [n_start, n_end] = T::split_range_n(config_.intermediate_size, ith, nth);
570	        for (int i = 0; i < m_local_num_[expert_idx]; i++) {
571	          float* gate_output_ptr = &m_local_gate_output_ptr_[expert_idx][i * config_.intermediate_size];
572	          float* up_output_ptr = &m_local_up_output_ptr_[expert_idx][i * config_.intermediate_size];
573	          for (int j = n_start; j < n_end; j++) {
574	            gate_output_ptr[j] = act_fn(gate_output_ptr[j]) * up_output_ptr[j];
575	          }
576	        }
577	      };
578	      MOE_DIRECT_OR_POOL_BY_VAR(nth * activated_expert, up_gate_fn);
579	    }
580	
581	#ifdef FORWARD_TIME_PROFILE
582	    PROFILE_RECORD_TIME_STAMP("act");
583	#endif
584	
585	    pool->do_work_stealing_job(
586	        activated_expert, nullptr,
587	        [this](int task_id) {
588	          int expert_idx = m_expert_id_map_[task_id];
589	          down_ba_[expert_idx]->from_mat(m_local_num_[expert_idx], m_local_gate_output_ptr_[expert_idx]);
590	        },
591	        nullptr);
592	
593	#ifdef FORWARD_TIME_PROFILE
594	    PROFILE_RECORD_TIME_STAMP("quant_down_input");
595	#endif
596	
597	    int nth_down = T::recommended_nth_down(config_.hidden_size, mode);
598	    pool->do_work_stealing_job(
599	        mth * nth_down * activated_expert, nullptr,
600	        [this, qlen, nth_down, oc, &cblas_gemm_s8s8s32, devide_elements_size, mth](int task_id) {
601	          int expert_idx = m_expert_id_map_[task_id / (nth_down * mth)];
602	          task_id = task_id % (nth_down * mth);
603	          int ith = task_id % nth_down;
604	          int jth = task_id / nth_down;
605	          if (jth * T::M_BLOCK >= m_local_num_[expert_idx]) return;
606	          int m_block = T::M_BLOCK;
607	          if ((jth + 1) * T::M_BLOCK > m_local_num_[expert_idx]) {
608	            m_block = m_local_num_[expert_idx] - jth * T::M_BLOCK;
609	          }
610	          int8_t* a_ptr = ((int8_t*)down_ba_[expert_idx]->a) + jth * T::M_BLOCK * config_.intermediate_size;
611	          int8_t* b_ptr = select_down_B_ptr_(expert_idx, ith, devide_elements_size);
612	          int32_t* c_ptr =
613	              ((int32_t*)down_bc_[expert_idx]->c) + ith * T::N_BLOCK_DOWN + jth * T::M_BLOCK * config_.hidden_size;
614	          cblas_gemm_s8s8s32(KernelCblasRowMajor, KernelCblasNoTrans, KernelCblasTrans, KernelCblasFixOffset, m_block,
615	                             T::N_BLOCK_DOWN, config_.intermediate_size, 1.0, a_ptr, config_.intermediate_size, 0,
616	                             b_ptr, config_.intermediate_size, 0, 0.0, c_ptr, config_.hidden_size, &oc);
617	
618	          T::apply_scale(m_local_num_[expert_idx], config_.hidden_size, m_local_down_output_ptr_[expert_idx],
619	                         down_ba_[expert_idx].get(), down_bb_[expert_idx].get(), down_bc_[expert_idx].get(), ith,
620	                         nth_down, T::N_BLOCK_DOWN, jth);
621	        },
622	        nullptr);
623	
624	#ifdef FORWARD_TIME_PROFILE
625	    PROFILE_RECORD_TIME_STAMP("down");
626	#endif
627	
628	    // Merge k experts per token with weights
629	    size_t block_dim = 512;
630	    size_t block_num = (config_.hidden_size + block_dim - 1) / block_dim;
631	    pool->do_work_stealing_job(
632	        qlen * block_num, nullptr,
633	        [this, k, expert_ids, weights, output, block_dim, block_num](int i) {
634	          int q_idx = i / block_num;
635	          int block_idx = i % block_num;
636	          int e_start = block_idx * block_dim;
637	          int e_end =
638	              ((block_idx + 1) * block_dim) < config_.hidden_size ? ((block_idx + 1) * block_dim) : config_.hidden_size;
639	          for (int e = e_start; e < e_end; e++) {
640	            float sum = 0;
641	            for (int j = 0; j < k; j++) {
642	              if (config_.should_skip_expert(expert_ids[q_idx * k + j])) {
643	                continue;
644	              }
645	              sum += weights[q_idx * k + j] * ((float*)m_local_down_output_ptr_[expert_ids[q_idx * k + j]])
646	                                                  [m_local_pos_[q_idx][j] * config_.hidden_size + e];
647	            }
648	            ((float*)output)[q_idx * config_.hidden_size + e] = sum;
649	          }
650	        },
651	        nullptr);
652	
653	#ifdef FORWARD_TIME_PROFILE
654	    time_perf_name = std::string("[moe] ") + ((mode == 'p') ? "layer prefill" : "decode layer ") +
655	                     std::to_string(config_.layer_idx) + " tp_part_idx: " + std::to_string(tp_part_idx);
656	    perf_report();
657	#endif
658	  }
